target:
private boolean isComponentPartOfCurrentMenu(MenuElement root,Component c) {
        MenuElement children[];
        int i,d;

        if (root == null)
            return false;

        if(root.getComponent() == c)
            return true;
        else {
            children = root.getSubElements();
            for(i=0,d=children.length;i<d;i++) {
                if(isComponentPartOfCurrentMenu(children[i],c))
                    return true;
            }
        }
        return false;
    }

prediction:
private boolean isComponentPartOfCurrentMenu(MenuElement menuElement, Component c) {
        if(menuElement == null)
            return false;
        if(menuElement.getComponent() == c)
            return true;
        if(menuElement.getSubElements() == null)
            return false;
        for(int j=0;j<menuElement.getSubElements().length;j++) {
            if(isComponentPartOfCurrentMenu(menuElement.getSubElements()[j],c))
                return true;
        }
        return false;
    }

