@Override
    public void setHead(int displayId, boolean enchanted, DisplayHeadType displayHeadType, String displayHeadValue, Player player, boolean useSecondaryAction) {
        CraftPlayer cp = (CraftPlayer) player;
        ServerGamePacketListenerImpl connection = cp.getHandle().connection;

        List<SynchedEntityData.DataValue<?>> data = new ArrayList<>();
        ItemStack head = HeadUtils.getHead(displayHeadType, displayHeadValue, player);
        if (enchanted) head.addUnsafeEnchantment(Enchantment.MENDING, 1);

        data.add(SynchedEntityData.DataValue.create(new EntityDataAccessor<>(22, EntityDataSerializers.ITEM_STACK), CraftItemStack.asNMSCopy(head)));
        data.add(SynchedEntityData.DataValue.create(new EntityDataAccessor<>(23, EntityDataSerializers.BYTE), (byte) (useSecondaryAction? 1 : 0)));
        connection.send(new ClientboundSetEntityDataPacket(displayId, data));
    }

